// One definition of "files nobody reviews by hand" — vendored/build output,
// lockfiles, generated ABIs, or anything so large it's almost certainly
// machine-written. Shared by the change summary (which folds them into a
// collapsed group) and the diff layer (which subtracts them from the agent's
// diff, the coverage gate, and the rendered review). Keeping one source of
// truth means a regenerated 20k-line ABI can't bury the real change in the
// summary *and* can't balloon the review into tens of thousands of DOM rows
// that crash the renderer — both screens agree on exactly which files are noise.
//
// Pure (path + line-count only) so the low-level git layer can import it with
// no risk of a cycle.
/** A single file's diff bigger than this (added + removed) reads as generated. */
export const REVIEW_NOISE_MAX_LINES = 1500;
/** Vendored/build/generated artifact paths nobody reviews by hand. */
export function isGeneratedPath(path) {
    const p = path.toLowerCase();
    return (/(^|\/)(dist|build|out|node_modules|vendor|\.next|coverage|__generated__)\//.test(p) ||
        /(^|\/)(package-lock\.json|yarn\.lock|pnpm-lock\.yaml|composer\.lock|cargo\.lock|go\.sum)$/.test(p) ||
        /\.(min\.js|min\.css|map|lock)$/.test(p) ||
        /(^|\/)abis?\//.test(p) ||
        /\.abi\.json$/.test(p));
}
/** True when a file is review noise: generated by path, or simply too large. */
export function isReviewNoise(path, changedLines) {
    return isGeneratedPath(path) || changedLines >= REVIEW_NOISE_MAX_LINES;
}
